"use client";

/**
 * HIP4Provider — optional React context for cleaner hook DX.
 *
 * Wrap your app to avoid passing `client` to every hook:
 *
 *   <HIP4Provider testnet={true}>
 *     <App />
 *   </HIP4Provider>
 *
 * Then use hooks without the client arg:
 *   const { markets } = useMarkets()     // reads from context
 *   const { bids } = useOrderbook(coin)  // reads from context
 *
 * You can still pass client explicitly to any hook — it takes priority:
 *   const { markets } = useMarkets(explicitClient)
 */

import React, { createContext, useContext } from "react";
import { useHIP4Client } from "@/hooks/hip4/use-hip4-client";
import type { HIP4Client } from "@/hooks/hip4/use-hip4-client";

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

/**
 * Internal context value. Default is null — returned by useHIP4Context()
 * when no HIP4Provider is in the tree.
 */
const HIP4Context = createContext<HIP4Client | null>(null);

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface HIP4ProviderProps {
  /**
   * Connect to Hyperliquid testnet. Default: false (mainnet).
   */
  testnet?: boolean;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  children?: any;
}

// ---------------------------------------------------------------------------
// Provider component
// ---------------------------------------------------------------------------

/**
 * Provides an HIP4Client to all descendant hooks via React context.
 *
 * The client is created once per Provider mount (via useHIP4Client) and
 * closed on unmount. Children can call useHIP4Context() to read it, or
 * continue passing the client explicitly — explicit always wins.
 */
export function HIP4Provider({
  testnet = false,
  children,
}: HIP4ProviderProps): React.ReactElement {
  const client = useHIP4Client({ testnet });

  return React.createElement(
    HIP4Context.Provider,
    { value: client },
    children,
  );
}

// ---------------------------------------------------------------------------
// Context hook
// ---------------------------------------------------------------------------

/**
 * Returns the HIP4Client from the nearest HIP4Provider ancestor, or null
 * if no provider is present in the tree.
 *
 * Hooks use this internally: if you don't pass `client` explicitly they
 * fall back to this value. If both are absent, hooks throw a clear error.
 */
export function useHIP4Context(): HIP4Client | null {
  return useContext(HIP4Context);
}

/**
 * useHIP4Client — creates and caches a Hyperliquid client bundle.
 *
 * Wraps @nktkas/hyperliquid transports and clients into a single object.
 * The client is created once per component mount and cached in a ref.
 *
 * Usage:
 *   const client = useHIP4Client({ testnet: true });
 *   const mids = await client.info.allMids();
 */

"use client";

import { useRef, useEffect } from "react";
import { HttpTransport, InfoClient, SubscriptionClient, WebSocketTransport } from "@nktkas/hyperliquid";

export interface UseHIP4ClientOptions {
  /** Connect to testnet. Default: false (mainnet). */
  testnet?: boolean;
  /** @deprecated No-op — builder config belongs at the order level, not the client level. */
  builderAddress?: string;
  /** @deprecated No-op — builder config belongs at the order level, not the client level. */
  builderFee?: number;
}

/** The client bundle returned by useHIP4Client */
export interface HIP4Client {
  info: InfoClient;
  sub: SubscriptionClient;
  close: () => void;
}

/**
 * Create and cache a Hyperliquid client for the lifetime of the component.
 *
 * The client is stable across re-renders. A new client is only created
 * if `testnet` changes (which should be uncommon).
 */
export function useHIP4Client(opts: UseHIP4ClientOptions = {}): HIP4Client {
  const { testnet = false } = opts;

  const clientRef = useRef<HIP4Client | null>(null);
  const testnetRef = useRef<boolean>(testnet);

  if (clientRef.current === null || testnetRef.current !== testnet) {
    // Close old client if it exists
    if (clientRef.current !== null) {
      clientRef.current.close();
    }

    const httpTransport = new HttpTransport({ isTestnet: testnet });
    const wsTransport = new WebSocketTransport({ isTestnet: testnet });

    clientRef.current = {
      info: new InfoClient({ transport: httpTransport }),
      sub: new SubscriptionClient({ transport: wsTransport }),
      close: () => {
        wsTransport.close();
      },
    };
    testnetRef.current = testnet;
  }

  // Close the client on unmount
  useEffect(() => {
    return () => {
      if (clientRef.current) {
        clientRef.current.close();
        clientRef.current = null;
      }
    };
  }, []);

  return clientRef.current!;
}
